import{m as o}from"./module.esm-BjLr86Y6.js";window.authLogic=()=>({email:"",password:"",rememberMe:!1,loading:!1,async login(){this.loading=!0;try{const e=await fetch("/api/auth/login",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email:this.email,password:this.password})}),t=await e.json();if(!e.ok)throw new Error(t.message||"Login failed");localStorage.setItem("fof_token",t.token),localStorage.setItem("fof_user",JSON.stringify({name:t.name,id:t.userId})),window.dispatchEvent(new CustomEvent("notify",{detail:{message:"Logged in successfully",type:"success"}})),setTimeout(()=>window.location.href="/index.html",1500)}catch(e){window.dispatchEvent(new CustomEvent("notify",{detail:{message:e.message,type:"error"}}))}finally{this.loading=!1}}});window.Alpine=o;o.start();
